// src/nodes/BaseNode.js
import React from 'react';
import { Handle, Position } from 'reactflow';
import './node.css';

export const BaseNode = ({ 
  id, 
  data,
  title = "Node",
  accentColor = "#3b82f6",
  inputHandles = [],
  outputHandles = [],
  className = "",
  children
}) => {
  // Calculate positions for multiple handles (n8n style - spaced evenly)
  const getHandlePosition = (index, total, isInput = true) => {
    if (total <= 1) return { top: '50%' };
    
    // Space handles evenly from 25% to 75% of node height
    const start = 25;
    const end = 75;
    const spacing = (end - start) / (total - 1);
    const top = start + (index * spacing);
    return { 
      top: `${top}%`,
      [isInput ? 'left' : 'right']: '-6px'
    };
  };

  return (
    <div className={`vs-node ${className}`}>
      <div className="vs-node-header">
        <span>{title}</span>
        {/* Optional: Add node status indicator */}
        {data?.status && (
          <span style={{ 
            fontSize: '10px', 
            background: 'rgba(255,255,255,0.2)', 
            padding: '2px 6px', 
            borderRadius: '10px' 
          }}>
            {data.status}
          </span>
        )}
      </div>
      <div className="vs-node-body">
        {children}
      </div>
      
      {/* Input Handles on LEFT side */}
      {inputHandles.map((handle, index) => (
        <Handle
          key={`in-${id}-${handle.id || index}`}
          type="target"
          position={Position.Left}
          id={handle.id || `input-${index}`}
          style={{
            top: `${25 + (index * (50 / Math.max(inputHandles.length - 1, 1)))}%`,
            left: '-6px',
            ...handle.style
          }}
          className="input-handle"
        />
      ))}
      
      {/* Output Handles on RIGHT side */}
      {outputHandles.map((handle, index) => (
        <Handle
          key={`out-${id}-${handle.id || index}`}
          type="source"
          position={Position.Right}
          id={handle.id || `output-${index}`}
          style={{
            top: `${25 + (index * (50 / Math.max(outputHandles.length - 1, 1)))}%`,
            right: '-6px',
            ...handle.style
          }}
          className="output-handle"
        />
      ))}
      
      {/* Connection indicators for empty nodes */}
      {inputHandles.length === 0 && (
        <Handle
          type="target"
          position={Position.Left}
          id="default-input"
          style={{ top: '50%', left: '-6px' }}
          className="input-handle"
        />
      )}
      
      {outputHandles.length === 0 && (
        <Handle
          type="source"
          position={Position.Right}
          id="default-output"
          style={{ top: '50%', right: '-6px' }}
          className="output-handle"
        />
      )}
    </div>
  );
};

export const useNodeState = (initialData, dataObject) => {
  const [state, setState] = React.useState(initialData);
  
  const updateState = (key, value) => {
    const newState = { ...state, [key]: value };
    setState(newState);
    
    if (dataObject && key in newState) {
      dataObject[key] = value;
    }
  };
  
  return [state, updateState];
};
